const Q_HISTORY_2012=[{"id": "objective>History>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing as indicated above is given to you?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">History</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">English</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is asking about the subject indicated in the id. The id contains 'History', which suggests that the subject being referred to is History.</div>", "topic": "HISTORY"}, {"id": "objective>History>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nok civilization suggests that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Nigeria passed through different stages of development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">civilization in the area began with the Stone Age</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the people of Nigeria came from the East</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nigerian civilization is related to that of Greek</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nok civilization, which existed in Nigeria around 500 BC, is known for its highly advanced social system and its early use of iron smelting technology. This suggests that Nigeria passed through different stages of development, which is the first option. The Nok civilization does not have any known connections to the East or to Greek civilization, and while it did exist during a time period that could be considered part of the 'Stone Age', it is not accurate to say that civilization in the area began with the Stone Age, as there were likely earlier, less advanced societies in the area before the Nok.</div>", "topic": "HISTORY"}, {"id": "objective>History>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The development of mircoliths is associated with the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Middle Age Stone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Late Stone Age</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iron Age</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Early Stone Age</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The middle Stone Age was characterized by facetted butts; the Iron Age by the development of iron and other metallic weapons and the Early Stone Age by bifaces, cleavers,picks and choppers</div>", "topic": "EARLY CENTRES OF CIVILIZATION"}, {"id": "objective>History>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In pre-colonial Nigeria, intergroup contacts were encourage mostly by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">economic interdependence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">military alliance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marriage ties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">political ties</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In pre-colonial Nigeria, intergroup contacts were mostly encouraged by economic interdependence. Different groups had different resources and products, and trade between groups was a common way to obtain what was not locally available. This economic interdependence fostered peaceful relations and encouraged contacts between different groups.</div>", "topic": "LAND AND PEOPLES OF THE NIGERIA AREA"}, {"id": "objective>History>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the most important source of the history of the Hausa states?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tarikh-as Sudan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The European account</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Kano Chronicle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Arab traders' account</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Kano Chronicle mentions only the relationship between Kano and neighbouring states; the Europeana ccounts contain information about Nigeria's coastal states while Tarikh-al- Sudan supplies information on mainly Western and central Sudanese states</div>", "topic": "HAUSA STATES"}, {"id": "objective>History>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The collapse of Kanem under Dunama Debalemi was attributed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poor economic system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of a standing army</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conflict among the ruling class</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of a sound political structure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The collapse of Kanem under Dunama Debalemi was attributed to conflict among the ruling class. This led to internal strife and instability, weakening the state and leading to its eventual collapse. The other options, such as poor economic system, lack of a standing army, and lack of a sound political structure, could contribute to a state's collapse, but in the case of Kanem under Dunama Debalemi, it was primarily due to conflict among the ruling class.</div>", "topic": "KANEM-BORNO"}, {"id": "objective>History>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Yoruba background to the Oba of Benin is emphasized by the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">similarities of Benin and Ife arts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">similarities in their political structures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relationship between Oranmiyan and Ogiso dynasties</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oranmiyan legend in Benin history</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There was no relationship between the Oranmiyan and Ogiso Dynasties the latter of which had been superceded by the Republican system; the Oranmiyan connection with Benin history produced similarities in Ife and Benin arts as well as in their political structures</div>", "topic": "BENIN : RELATIONS WITH NEIGHBOURS"}, {"id": "objective>History>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">European traders did not venture into the interior of Nigeria before the 19th century because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they were ignorant of the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the African middlemen served their needs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of their fear of the African middlemen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they were very few in number</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">European traders did not venture into the interior of Nigeria before the 19th century because the African middlemen served their needs. The African middlemen were responsible for bringing goods from the interior to the coast for trade with the Europeans. This made it unnecessary for the Europeans to venture into the interior.</div>", "topic": "EUROPEAN PENETRATION AND IMPACT : THE ACTIVITIES OF THE TRADING COMPANIES"}, {"id": "objective>History>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Africans transported across the Atlantic as slaves were mostly</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">people with criminal records</div>", "<div style=\"font-family:Cambria;font-size:17px;\">able-bodied men</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disabled persons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people with low income</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Disabled persons as well as old persons and children were not taken as they would not be able to work on sugarcane and tobacco plantations in America where they were taken to</div>", "topic": "TRANS-ATLANTIC SLAVE TRADE"}, {"id": "objective>History>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The jihadists emerged victorious in Gobir because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">their cause was just</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Hausa rulers were divided</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they had superior weapons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the masses supported them</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> The masses supported them. The question is self explanatory in relation to the answer.</div>", "topic": "JIHADS"}, {"id": "objective>History>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rabeh's greatest challenge after conquering Borno was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">normalizing relations with Sokoto Caliphate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rebuilding the armed forces</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reviving the ailing economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">safeguarding the religion of Islam</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rabeh had an efficient army at that time and his immediate aim certainly did not include establishing any contact with the Sokoto caliphate as he saw  <br/> himself as another Muslim reformer</div>", "topic": "KANEM-BORNO : BORNO UNDER RABEH"}, {"id": "objective>History>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Christianity spread fast in Nigeria because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">was associated with Western education</div>", "<div style=\"font-family:Cambria;font-size:17px;\">had superior spiritual appeal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preached social equality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">was opposed to oppression by rulers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Christianity spread fast in Nigeria largely because it was associated with Western education. During the colonial era, Christian missionaries established schools and provided Western education to the locals. This education was seen as a means to better opportunities and a better life, which attracted many Nigerians to Christianity. The other options, while they may have played a role, were not the primary reasons for the rapid spread of Christianity in Nigeria.</div>", "topic": "SIERRA LEONE, LIBERIA AND CHRISTIAN MISSIONARY ACTIVITIES IN WEST AFRICA : THE ACTIVITIES AND IMPACT OF CHRISTIAN MISSIONARIES."}, {"id": "objective>History>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Ibadan-Ijebu relations in the 19th Century became hostile as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">boundary disputes between them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">succession to the Ijebu throne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">British annexation of Lagos</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibadan's attempt to reach the coast</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The hostility between Ibadan and Ijebu in the 19th century was due to Ibadan's attempt to reach the coast. Ibadan, a powerful Yoruba state, was trying to expand its influence and control trade routes, including those leading to the coast. This brought it into conflict with Ijebu, which was also a powerful state and controlled some of the coastal areas.</div>", "topic": "YORUBALAND : THE PEACE TREATY OF 1886 AND ITS AFTERMATH"}, {"id": "objective>History>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Ekiti Parapo was aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">checking European inroad into Yorubaland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">restoring the dignity of the Alaafin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing the powers of Ibadan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forming a federated government</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ibadan had grown to become the most powerful Yoruba state whose administrative over other Yoruba states and towns had become oppressive and therefore unpopular</div>", "topic": "YORUBALAND : THE FALL OF THE OLD OYO EMPIRE"}, {"id": "objective>History>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Uzama title holders in Benin Kingdom were responsible for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">advising the Oba in the administration of the Kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">punishing erring members of the royal family</div>", "<div style=\"font-family:Cambria;font-size:17px;\">defending the Kingdom from external attacks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">settling disputes between the Oba and other chiefs</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Uzama title holders in Benin Kingdom were a group of high-ranking chiefs who were responsible for advising the Oba in the administration of the Kingdom. They were part of the Oba's council and played a significant role in the governance of the kingdom.</div>", "topic": "BENIN : INTERNAL POLITICAL DEVELOPMENT"}, {"id": "objective>History>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Britain suppressed the trans-Atlantic slave trade because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">there was no more market for slaves in America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it had become very inhuman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Christian missions preached against it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it became unfavourable to her industrial progress</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Following the Industrial Revolution, the European countries needed raw materials for their industries not slaves who used to provide cheap manual labour</div>", "topic": "THE SUPPRESSION OF THE TRANS-ATLANTIC SLAVE TRADE."}, {"id": "objective>History>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main goal of the British expedition against the Aro was to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">destroy the Ibini-Ukpabi oracle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">eliminate all opposition to their presence in the hinterland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pave the way for the Christianization of Igboland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberate the Igbo from Aro bondage</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Eliminate all opposition to their presence in the hinterland</div>", "topic": "COLONIAL ADMINISTRATION AFTER THE AMALGAMATION : INDIRECT RULE – REASONS, WORKING AND EFFECTS"}, {"id": "objective>History>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major reason for the introduction of indirect rule in Northern Nigeria was to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ensure perfect control of the economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">further weaken the position of the elite class</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assist the Christian missionaries in their activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secure cheap labour for railway construct</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Control of the economy would grant them unhindered access to raw materials for the European industries and ready markets for the products from the industries</div>", "topic": "COLONIAL ADMINISTRATION AFTER THE AMALGAMATION : INDIRECT RULE – REASONS, WORKING AND EFFECTS"}, {"id": "objective>History>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nationalist activities developed earlier in British West Africa than in French West Africa because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">British colonies were accorded equal status with Britain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Britain had more colonies than France</div>", "<div style=\"font-family:Cambria;font-size:17px;\">African chiefs in French colonies were highly respected</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the systems of administration adopted by the colonial powers</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The systems of administration adopted by the colonial powers played a significant role in the development of nationalist activities. In British West Africa, the indirect rule system allowed for some level of self-governance and political awareness, which fostered nationalist activities. On the other hand, French West Africa was under direct rule, which was more restrictive and did not encourage political participation by the locals. Therefore, nationalist activities developed earlier in British West Africa than in French West Africa due to the different systems of administration adopted by the colonial powers.</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE"}, {"id": "objective>History>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main reason for the construction of the railway from Port-Harcourt into the hinterland was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">discovery of tin in Jos area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discovery of a deep sea harbor at Port-Harcourt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">discovery of coal at Udi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">need to evacuate export crops from the hinterland</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coal is a very heavy mineral which cannot be carried by road transport</div>", "topic": "COLONIAL ECONOMY"}, {"id": "objective>History>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the colonial period, agricultural policy in Nigeria was designed to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">raise the financial base of the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the economy compete favourably in the world market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide raw materials for British industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demonstrate Britain's concern for the development of its colonies</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the colonial period, the agricultural policy in Nigeria was designed to provide raw materials for British industries. The colonial masters established an economic system primarily to provide raw materials for their industries back home. This was done through the cultivation of cash crops such as cocoa, rubber, palm oil, etc. which were exported to Britain to feed its industries.</div>", "topic": "COLONIAL ECONOMY"}, {"id": "objective>History>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Youth Movement collapsed as a result of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its failure to win elections</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of funds to run its affairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the harassment of its leadership by government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the break-up of its leadership</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian Youth Movement (NYM) collapsed as a result of the break-up of its leadership. The NYM was a Nigerian nationalist organization that emerged in 1934 and gained significant popularity in the 1940s. It was the first Nigerian nationalist organization to gain wide spread across the country and its collapse was due to internal leadership conflicts.</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE"}, {"id": "objective>History>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The NCNC London Delegate pressed for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">free primary education for all Nigerian children</div>", "<div style=\"font-family:Cambria;font-size:17px;\">autonomy for the regions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a revision of the Richards Constitution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">outright independence for Nigeria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It, among other things not listed here except the correct option, sought the establishment of a legislative house in each of the four British colonial territories</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE"}, {"id": "objective>History>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Lyttlelton Constitution is considered a landmark in the history of Nigeria, because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">created a federal structure of government for the country</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made ministers accountable to the electorate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recognized Lagos as a federal territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gave ministers full authority over their ministries</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Created a federal structure of government for the country</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE"}, {"id": "objective>History>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Protests by trade unions in Nigeria during the colonial period were aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">achieving political independence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishing more industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">obtaining specific benefits for members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fighting corruption among government officials</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the colonial period, trade unions in Nigeria were primarily concerned with the welfare of their members. They protested to obtain specific benefits for their members such as better wages, improved working conditions, and other labor rights. This is the primary function of trade unions, to protect and promote the interests of their members. Therefore, the correct answer is 'obtaining specific benefits for members'. The other options are not the primary goals of trade unions. Achieving political independence was a national goal, not specifically a trade union goal. Establishing more industries and fighting corruption among government officials, while important, were not the main focus of trade union protests during the colonial period.</div>", "topic": "COLONIAL ADMINISTRATION AFTER THE AMALGAMATION : RESISTANCE TO COLONIAL RULE"}, {"id": "objective>History>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following served as federal ministers under the Tafawa Balewa Administration?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Alhaji Muhammadu Ribadu and Chief Festus Okotie-Eboh.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief Kolawole Balogun and Alhaji Adamu Ciroma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alhaji Muhammadu Inuwa Wada and Chief Richard Akinjide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chief Aja Nwachukwu and Alhaji Umaru Dikko</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alhaji Muhammadu Ribadu and Chief Festus Okotie-Eboh served as federal ministers under the Tafawa Balewa Administration. Alhaji Muhammadu Ribadu was the first Minister of Defence in Nigeria, and Chief Festus Okotie-Eboh was the Minister of Finance. The Tafawa Balewa Administration was the government in power in Nigeria from 1960 to 1966, during the First Republic.</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE : PARTY POLITICS"}, {"id": "objective>History>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important function of FEDECO during the 1979 elections was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">establishing party offices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promulgating the new constitution into law</div>", "<div style=\"font-family:Cambria;font-size:17px;\">swearing-in of elected officials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">delineating electoral constituencies</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Establishment of party offices was done by political parties; promulgation of the 1979 constitution into law by the then Federal Military Government while elected officials were  <br/> sworn in by either the Chief Justice, Chief Judge (state Governors) or speakers of state houses of assembly (for legislators)</div>", "topic": "NIGERIA INDEPENDENCE"}, {"id": "objective>History>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major reason for the military intervention in Nigeria's politics in 1966 was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pro-West posture of Nigeria's foreign policy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over-bearing power of traditional rulers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attempt by government to retire top military officers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crisis of the 1964 General Elections</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The crisis was exacerbated by that which resulted by the massively rigged Western Regional Election of 1965 which led to the total break-down of law and order</div>", "topic": "NIGERIA POLITICS"}, {"id": "objective>History>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Major General Aguiyi-Ironsi introduced a unitary system of government because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it was the wish of the people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of the command structure of the military</div>", "<div style=\"font-family:Cambria;font-size:17px;\">he wanted more revenue for the central government</div>", "<div style=\"font-family:Cambria;font-size:17px;\">other military officers were planning to overthrow him.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Major General Aguiyi-Ironsi introduced a unitary system of government because of the command structure of the military. In a military system, there is a central command that controls all units. This is similar to a unitary system of government where the central government has all the powers and the states or provinces are administrative divisions. The central government can delegate powers to these divisions but it can also take back these powers.</div>", "topic": "THE GOWON REGIME : CHALLENGES AND ACHIEVEMENTS"}, {"id": "objective>History>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The strategy for accelerated agricultural development of the Obasanjo regime in the 1970's focused on</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">improving transportation network to the rural areas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishing agro-allied industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">achieving food self-sufficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">establishing new marketing boards</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The strategy for accelerated agricultural development of the Obasanjo regime in the 1970's focused on achieving food self-sufficiency. This was a part of the National Accelerated Food Production Programme (NAFPP) which was launched in 1972. The main aim of this programme was to increase the production of staple foods like rice, maize, and cassava to achieve food self-sufficiency. This was done by providing farmers with improved seeds, fertilizers, and other inputs.</div>", "topic": "THE OBASANJO REGIME : CHALLENGES AND ACHIEVEMENTS"}, {"id": "objective>History>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Berber scholar, al-Mukhtar, contributed to the success of the Masina Jihad by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fighting alongside Seju Ahmadu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">preparing the ground through the Qadiriyyah Brotherhood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mobilizing various groups to fight for Seku Ahmadu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appealing to Ardo Moudo to support Seku Ahmadu</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">He started an Islamic revival in the Niger bend and Masina thus preaching the tenets of the Quadriyyah Brotherhood which later formed the  <br/> basis for the launching of Seku Ahmadu's Jihad</div>", "topic": "ISLAMIC REFORM MOVEMENTS AND STATE BUILDING IN WEST AFRICA"}, {"id": "objective>History>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The establishment of Freetown in 1822 facilitated</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the settlement of freed slaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Christian missionary activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humanitarian activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the improvement of agriculture</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Freetown was established in 1822 by the British as a home for freed slaves. The British had abolished the slave trade in 1807 and needed a place for freed slaves to settle. Freetown, in Sierra Leone, was chosen for this purpose. Therefore, the establishment of Freetown facilitated the settlement of freed slaves.</div>", "topic": "SIERRA LEONE, LIBERIA AND CHRISTIAN MISSIONARY ACTIVITIES IN WEST AFRICA"}, {"id": "objective>History>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nineteenth century Egyptian nationalism principally aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">controlling the Suez Canal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">forming a constitutional government in Egypt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bringing down the monarchy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensuring Egyptian independence.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nineteenth-century Egyptian nationalism was primarily aimed at ensuring Egyptian independence. During this period, Egypt was under the control of the Ottoman Empire and later the British. The main goal of the nationalists was to gain independence from these foreign powers. The other options such as controlling the Suez Canal, forming a constitutional government in Egypt, and bringing down the monarchy were part of the broader nationalist agenda but were not the principal aim.</div>", "topic": "EGYPT UNDER MOHAMMED ALI AND KHEDIVE ISMAIL : THE RISE OF MOHAMMAD ALI AND HIS REFORMS"}, {"id": "objective>History>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Battle of Tel el-Kebir was fought between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the British and the Urabists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tawfiq and the Mahdists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Khedive and the Wafdists</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Napoleon and the Mamluks</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Urabis' seizure of power in Egypt to end foreign domination of the country eventually led to stiff opposition from the British which defeated the nationalists and occupied Egypt</div>", "topic": "EGYPT UNDER MOHAMMED ALI AND KHEDIVE ISMAIL : THE BRITISH OCCUPATION OF EGYPT"}, {"id": "objective>History>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Morocco was of strategic importance to the European countries because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">of its good climatic conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it was highly industrialized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it possessed good mineral resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it provided an entrance to the Mediterranean</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Morocco was of strategic importance to the European countries because it provided an entrance to the Mediterranean. The Mediterranean Sea is a significant waterway for trade and military purposes, and controlling access to it was a strategic advantage for any country. This is why European countries were interested in Morocco.</div>", "topic": "EUROPEAN PENETRATION AND IMPACT : THE OCCUPATION AND RESISTANCE BY AFRICANS"}, {"id": "objective>History>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mahdists revolt in the Sudan was successful</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They believed they had a superior faith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It enjoyed widespread support</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Egyptian army was poorly trained</div>", "<div style=\"font-family:Cambria;font-size:17px;\">General Gordon was an incompetent commander</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Mahdists revolt in Sudan was successful primarily due to the widespread support it enjoyed among the Sudanese people. The revolt was led by Muhammad Ahmad bin Abd Allah, who proclaimed himself the Mahdi, or the prophesied redeemer of the Islamic faith. His message resonated with the Sudanese people, who were dissatisfied with the oppressive rule of the Egyptian-Ottoman government. This led to a mass uprising against the government, which ultimately resulted in the establishment of a Mahdist state in Sudan. While the other options may have contributed to the success of the revolt, the key factor was the widespread support it received from the people.</div>", "topic": "THE MAHDI AND MAHDIYYA MOVEMENT IN THE SUDAN : COURSE"}, {"id": "objective>History>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sayyid Said increased the volume of trade with the Europeans by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">allowing them to take control of the trade with the hinterland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">replacing Indian middlemen with Europeans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allowing European consuls to reside in Zanzibar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">making English the lingua franca of Zanzibar</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The European consuls were to ensure compliance with commercial treaties signed between their countries and the Omani rulers and to protect citizens of their countries from  <br/> molestations</div>", "topic": "EXTERNAL INFLUENCES : EUROPEANS"}, {"id": "objective>History>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the main aims of the British conquest of Buganda was to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gain access to the cape of Good Hope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pain control of the gold mines of Bunyoro</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent other Europeans from controlling the source of the Nile</div>", "<div style=\"font-family:Cambria;font-size:17px;\">take control of the trade routes in the area</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The British conquest of Buganda, a kingdom in present-day Uganda, was primarily aimed at preventing other European powers from controlling the source of the Nile. The Nile was a strategic waterway that was crucial for trade and transportation. The British wanted to ensure their dominance in the region and prevent other European powers, such as the French or Germans, from gaining control over this important resource. This is why option 3 is the correct answer. The other options are incorrect because the British conquest of Buganda was not primarily about gaining access to the Cape of Good Hope, controlling gold mines, or taking control of trade routes in the area.</div>", "topic": "EXTERNAL INFLUENCES : EUROPEANS"}, {"id": "objective>History>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The survival of Ethiopia as an independent politic was as a result of the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">location of the kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alliance with some European powers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">strong economic base of the kingdom</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introduction of a compulsory military service</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethiopia is characterized by high plateaux, gorges and valleys as well as semi-desert lowlands which have protected the country from external invasion</div>", "topic": "ETHIOPIA IN THE 19TH CENTURY : MENELIK II AND ETHIOPIAN INDEPENDENCE"}, {"id": "objective>History>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Mfecane resulted in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">division and fragmentation of the Zulu nation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formation of the Ndebele state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in Boer influence in South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersal of the Zulu to the Katanga copper belt</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Mfecane, also known by the Sesotho name Difaqane or Lifaqane, was a period of widespread chaos and warfare among indigenous ethnic communities in southern Africa during the period between 1815 and about 1840. As King Shaka created the militaristic Zulu Kingdom in the territory between the Tugela River and Pongola River, his forces caused a wave of warfare and disruption to other tribes in the area. This was the cause of the formation of the Ndebele state, as the Ndebele people were forced to move northwards and establish a state of their own. Therefore, the correct answer is 'formation of the Ndebele state'.</div>", "topic": "THE MFECANE : CAUSES, COURSE AND CONSEQUENCES OF THE MFECANE"}, {"id": "objective>History>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The 1960 Sharpeville revolt was specifically against</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">labour laws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">land laws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pass laws</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marriage laws</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sharpeville massacre occurred on 21 March 1960, at the police station in the South African township of Sharpeville in Transvaal. The protest was against the pass laws. Pass laws were a form of internal passport system designed to segregate the population, manage urbanization, and allocate migrant labor. Also known as the natives' law, pass laws severely limited the movements of not only black African citizens, but other people as well by requiring them to carry pass books when outside their homelands or designated areas.</div>", "topic": "APARTHEID IN SOUTH AFRICA : INTERNAL REACTION AND THE SUPPRESSION OF AFRICAN NATIONALIST MOVEMENTS"}, {"id": "objective>History>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major consequence of the Great Trek was the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">restriction of movement of the whites in South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agitation for black-white equality in South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">annexation of white communities by the Africans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the expansion of white communities in South Africa</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Great Trek was a movement of Dutch-speaking colonists up into the interior of southern Africa in search of land where they could establish their own homeland, independent of British rule. This movement led to the establishment of several Boer republics and hence, the expansion of white communities in South Africa. The other options are incorrect because the Great Trek did not lead to restriction of movement of whites, agitation for black-white equality, or annexation of white communities by Africans.</div>", "topic": "APARTHEID IN SOUTH AFRICA : INTERNAL REACTION AND THE SUPPRESSION OF AFRICAN NATIONALIST MOVEMENTS"}, {"id": "objective>History>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One feature of European diplomacy in the scramble for Africa was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">exchanging of ambassadors among them</div>", "<div style=\"font-family:Cambria;font-size:17px;\">holding Africans hostage for negotiations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negotiating with African leaders for territories</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reconciling differences over territorial claims</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">European powers held conferences in which they signed treaties among themselves to settle disagreements among them over rival claims laid to African territories</div>", "topic": "EUROPEAN PENETRATION AND IMPACT"}, {"id": "objective>History>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The French colonial policy of assimilation failed in Africa because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">African culture was deeply rooted</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the African elite were opposed to it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it was not consistently implemented</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it was expensive to implement</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The French colonial policy of assimilation failed in Africa primarily because African culture was deeply rooted. Assimilation was a policy where the French aimed to turn the colonies into French provinces and the inhabitants into French citizens. However, the African culture was deeply rooted and diverse, making it difficult for the French to fully implement their policy. The Africans had their own traditions, languages, and ways of life that they were not willing to give up. This resistance to cultural change was a major reason why the policy of assimilation failed.</div>", "topic": "EUROPEAN PENETRATION AND IMPACT"}, {"id": "objective>History>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following was one of the demands of the National Congress of British West Africa?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Establishment of a university in each of the colonies.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expulsion of all Syrians and Lebanese from the colonies.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Election of Africans into each colony's council.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Restriction of the activities of Christian missionaries in the colonies.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The National Congress of British West Africa (NCBWA) was a political pressure group that emerged in 1920 to champion the rights of the indigenous people in the British West African colonies. One of their key demands was the inclusion of Africans in the legislative councils of the colonies. They believed that Africans should have a say in the governance of their own lands. Therefore, the correct answer is 'Election of Africans into each colony's council.'</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE"}, {"id": "objective>History>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The nationalist movement in Nigeria during the post-war period was primarily led by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">businessmen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the intelligentsia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">students</div>", "<div style=\"font-family:Cambria;font-size:17px;\">local chiefs</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nationalist movement in Nigeria during the post-war period was primarily led by the intelligentsia. The intelligentsia refers to the intellectual elite of a society, typically comprising intellectuals and social groups engaged in complex mental and creative labor directed to the development and dissemination of culture, encompassing academics, intellectuals and the literary intelligentsia. In the context of Nigeria, this group played a significant role in the nationalist movement, advocating for independence from colonial rule. They were able to articulate the aspirations of the people and mobilize them towards the goal of self-determination. Therefore, the correct answer is 'the intelligentsia'.</div>", "topic": "NATIONALISM, CONSTITUTIONAL DEVELOPMENTS AND INDEPENDENCE"}, {"id": "objective>History>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the objectives for the formation of the South African Native Congress in 1912 was to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">establish a political party</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage black participation in governance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">retrieve all lands seized by the whites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">integrate the various groups and races</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Integrate the various groups and races. The question is self explanatory in relation to the answer.</div>", "topic": "APARTHEID IN SOUTH AFRICA : INTERNAL REACTION AND THE SUPPRESSION OF AFRICAN NATIONALIST MOVEMENTS"}, {"id": "objective>History>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In 1973, Nigeria broke diplomatic relations with Israel because of Israel's</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">occupation of Egyptian territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">support for apartheid South Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">support for Biafra during the war</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raid on Entebbe airport in Uganda.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In 1973, Nigeria broke diplomatic relations with Israel due to Israel's occupation of Egyptian territory. This happened during the Yom Kippur War when Israel occupied the Sinai Peninsula, which is an Egyptian territory. Nigeria, being a member of the African Union and having close ties with Egypt, severed diplomatic ties with Israel in support of Egypt.</div>", "topic": "NIGERIA IN INTERNATIONAL ORGANIZATIONS : UNITED NATIONS ORGANIZATION"}, {"id": "objective>History>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">King Leopold's colonial ventures in the Congo were aimed at</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">making Belgium a great colonial power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carving out an empire for himself</div>", "<div style=\"font-family:Cambria;font-size:17px;\">putting a stop to domestic slave trade in the area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">introducing Western education to the people</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Leopold did not want to be left out of new territorial acquisitions in Africa following the encouragement of the French to do so by Bismarck of Germany following the  <br/> former's loss of the rich territories of Alsace and Lorraine to the former</div>", "topic": "COLONIAL ADMINISTRATION AFTER THE AMALGAMATION : INFRASTRUCTURE (TRANSPORTATION, POST AND TELECOMMUNICATION)"}, {"id": "objective>History>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Africa, the colonial authorities introduced modern means of transportation in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">develop the internal markets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase farmers' purchasing power</div>", "<div style=\"font-family:Cambria;font-size:17px;\">encourage urban development</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promote import-export trade</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The colonial authorities introduced modern means of transportation in Africa primarily to facilitate the movement of goods from the interior to the coast for export, and the import of goods from the colonial powers. This was done to promote import-export trade. The development of internal markets, increasing farmers' purchasing power, and encouraging urban development were secondary effects, not the primary intention of the colonial authorities.</div>", "topic": "COLONIAL ECONOMY : INFRASTRUCTURE (TRANSPORTATION, POST AND TELECOMMUNICATION)"}];
